import { NextRequest, NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import { verifyPassword } from "@/lib/password";
import {
  createSessionCookieValue,
  getSessionCookieName,
  SESSION_COOKIE_OPTIONS,
} from "@/lib/session";

export async function POST(request: NextRequest) {
  const formData = await request.formData();
  const fullNameRaw = formData.get("fullName");
  const passwordRaw = formData.get("password");
  const emailRaw = formData.get("email");
  const redirectToRaw = formData.get("redirectTo");

  const fullName = typeof fullNameRaw === "string" ? fullNameRaw.trim() : "";
  const password = typeof passwordRaw === "string" ? passwordRaw : "";
  const email =
    typeof emailRaw === "string" ? emailRaw.trim() || null : null;
  const redirectTo =
    typeof redirectToRaw === "string" && redirectToRaw.startsWith("/")
      ? redirectToRaw
      : "/feed";

  const fieldErrors: Record<string, string> = {};
  if (!fullName) fieldErrors.fullName = "Full name is required.";
  if (!password) fieldErrors.password = "Password is required.";
  if (Object.keys(fieldErrors).length > 0) {
    const params = new URLSearchParams({
      error: "Full name and password are required.",
      ...(redirectTo !== "/feed" && { from: redirectTo }),
    });
    return NextResponse.redirect(
      new URL(`/login?${params}`, request.url),
      302
    );
  }

  const members = await prisma.teamMember.findMany({
    where: {
      name: { equals: fullName.trim(), mode: "insensitive" },
      passwordHash: { not: null },
    },
  });

  if (members.length === 0) {
    const params = new URLSearchParams({
      error: "Invalid name or password.",
      ...(redirectTo !== "/feed" && { from: redirectTo }),
    });
    return NextResponse.redirect(
      new URL(`/login?${params}`, request.url),
      302
    );
  }

  if (members.length > 1 && !email) {
    const params = new URLSearchParams({
      error: "Multiple accounts with this name. Enter your email to log in.",
      ...(redirectTo !== "/feed" && { from: redirectTo }),
    });
    return NextResponse.redirect(
      new URL(`/login?${params}`, request.url),
      302
    );
  }

  let candidate = members[0];
  if (members.length > 1 && email) {
    const byEmail = members.find(
      (m) => m.email && m.email.toLowerCase() === email!.toLowerCase()
    );
    if (!byEmail) {
      const params = new URLSearchParams({
        error: "Invalid name or password.",
        ...(redirectTo !== "/feed" && { from: redirectTo }),
      });
      return NextResponse.redirect(
        new URL(`/login?${params}`, request.url),
        302
      );
    }
    candidate = byEmail;
  }

  const valid = await verifyPassword(password, candidate.passwordHash!);
  if (!valid) {
    const params = new URLSearchParams({
      error: "Invalid name or password.",
      ...(redirectTo !== "/feed" && { from: redirectTo }),
    });
    return NextResponse.redirect(
      new URL(`/login?${params}`, request.url),
      302
    );
  }

  const cookieValue = createSessionCookieValue(candidate.id);
  const res = NextResponse.redirect(new URL(redirectTo, request.url), 302);
  res.cookies.set(getSessionCookieName(), cookieValue, SESSION_COOKIE_OPTIONS);
  return res;
}
